// Parse Typeform webhook payload
const webhookData = $input.first().json;
const formResponse = webhookData.form_response || webhookData;

// Extract answers
const answers = {};
if (formResponse.answers) {
  formResponse.answers.forEach(answer => {
    const fieldRef = answer.field?.ref || answer.field?.id || '';
    if (answer.type === 'email') answers.email = answer.email || '';
    else if (answer.type === 'text') answers[fieldRef] = answer.text || '';
    else if (answer.type === 'choice') answers[fieldRef] = answer.choice?.label || '';
    else if (answer.type === 'choices') answers[fieldRef] = answer.choices?.labels || [];
  });
}

const leadData = {
  email: answers.email || answers.Email || '',
  industry: answers.industry || answers.Industry || '',
  location: answers.location || answers.Location || '',
  target_business: answers.target_business || answers['target-business'] || '',
  lead_sources: Array.isArray(answers.lead_sources || answers['lead-sources']) ? answers.lead_sources || answers['lead-sources'] : [],
  form_id: webhookData.form_id || '',
  submitted_at: formResponse.submitted_at || new Date().toISOString()
};

return [{
  json: {
    success: true,
    leadData: leadData
  }
}];

// Format leads as CSV
const leads = $input.all();
const csvHeaders = ['Company Name', 'Contact Name', 'Email', 'Phone', 'Location', 'Industry', 'Source'];
let csv = csvHeaders.join(',') + '\n';

leads.forEach(item => {
  const lead = item.json;
  const row = [
    lead.company_name || lead.company || '',
    lead.contact_name || lead.name || '',
    lead.email || '',
    lead.phone || '',
    lead.location || '',
    lead.industry || '',
    lead.source || 'Generated'
  ].map(field => `"${String(field).replace(/"/g, '""')}"`).join(',');
  csv += row + '\n';
});

return [{
  json: {
    csv: csv,
    leadCount: leads.length
  }
}];

